const input = $json;

const systemPrompt = `# Rol
Eres el Market Intelligence Agent del sistema Innexia AI Strategic Analysis Engine.

# Objetivo
Analizar el mercado de la oportunidad o iniciativa propuesta usando el contexto recibido y búsquedas web cuando sea útil.

# Instrucciones
- Identifica mercado objetivo, necesidades del cliente, tendencias, competidores, factores regulatorios, barreras y oportunidades.
- Si no hay datos exactos, usa supuestos razonables y decláralos.
- Si aplica, estima TAM, SAM y SOM de forma preliminar y cualitativa o semicuantitativa.
- No expliques tu razonamiento.
- Devuelve únicamente JSON válido.
- No incluyas markdown.
- No incluyas texto fuera del JSON.

# Formato de salida
{
  "market_analysis": {
    "market_overview": "",
    "target_market": [],
    "customer_needs": [],
    "industry_trends": [],
    "competitors": [
      {
        "name": "",
        "type": "",
        "strengths": [],
        "weaknesses": []
      }
    ],
    "regulatory_factors": [],
    "barriers_to_entry": [],
    "opportunities": [],
    "tam_sam_som": {
      "tam": "",
      "sam": "",
      "som": ""
    },
    "assumptions": []
  }
}

# Regla final
Devuelve únicamente JSON válido.`;

const userPayload = JSON.stringify(input);

const outputSchema = {
  type: "object",
  properties: {
    market_analysis: {
      type: "object",
      properties: {
        market_overview: { type: "string" },
        target_market: { type: "array", items: { type: "string" } },
        customer_needs: { type: "array", items: { type: "string" } },
        industry_trends: { type: "array", items: { type: "string" } },
        competitors: {
          type: "array",
          items: {
            type: "object",
            properties: {
              name: { type: "string" },
              type: { type: "string" },
              strengths: { type: "array", items: { type: "string" } },
              weaknesses: { type: "array", items: { type: "string" } }
            },
            required: ["name", "type", "strengths", "weaknesses"]
          }
        },
        regulatory_factors: { type: "array", items: { type: "string" } },
        barriers_to_entry: { type: "array", items: { type: "string" } },
        opportunities: { type: "array", items: { type: "string" } },
        tam_sam_som: {
          type: "object",
          properties: {
            tam: { type: "string" },
            sam: { type: "string" },
            som: { type: "string" }
          },
          required: ["tam", "sam", "som"]
        },
        assumptions: { type: "array", items: { type: "string" } }
      },
      required: ["market_overview", "target_market", "customer_needs", "industry_trends", "competitors", "regulatory_factors", "barriers_to_entry", "opportunities", "tam_sam_som", "assumptions"]
    }
  },
  required: ["market_analysis"]
};

return [{ json: { input, system_prompt: systemPrompt, user_payload: userPayload, output_schema: outputSchema } }];

let content = $json.text ?? $json.output ?? $json;

if (typeof content === 'string') {
  content = content.trim();

  if (content.startsWith('```')) {
    content = content
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/, '')
      .replace(/```$/, '')
      .trim();
  }

  content = JSON.parse(content);
}

if (content && typeof content === 'object' && content.__structured__output__object) {
  content = content.__structured__output__object;
}

content.market_analysis = content.market_analysis || {};
content.market_analysis.market_overview = content.market_analysis.market_overview || "";
content.market_analysis.target_market = Array.isArray(content.market_analysis.target_market) ? content.market_analysis.target_market : [];
content.market_analysis.customer_needs = Array.isArray(content.market_analysis.customer_needs) ? content.market_analysis.customer_needs : [];
content.market_analysis.industry_trends = Array.isArray(content.market_analysis.industry_trends) ? content.market_analysis.industry_trends : [];
content.market_analysis.competitors = Array.isArray(content.market_analysis.competitors) ? content.market_analysis.competitors : [];
content.market_analysis.regulatory_factors = Array.isArray(content.market_analysis.regulatory_factors) ? content.market_analysis.regulatory_factors : [];
content.market_analysis.barriers_to_entry = Array.isArray(content.market_analysis.barriers_to_entry) ? content.market_analysis.barriers_to_entry : [];
content.market_analysis.opportunities = Array.isArray(content.market_analysis.opportunities) ? content.market_analysis.opportunities : [];
content.market_analysis.tam_sam_som = content.market_analysis.tam_sam_som || {};
content.market_analysis.assumptions = Array.isArray(content.market_analysis.assumptions) ? content.market_analysis.assumptions : [];

return [{ json: content }];

const data = $json;

if (!data.market_analysis || typeof data.market_analysis !== 'object') {
  throw new Error('market_analysis faltante o inválido');
}

data.market_analysis.target_market = Array.isArray(data.market_analysis.target_market) ? data.market_analysis.target_market : [];
data.market_analysis.customer_needs = Array.isArray(data.market_analysis.customer_needs) ? data.market_analysis.customer_needs : [];
data.market_analysis.industry_trends = Array.isArray(data.market_analysis.industry_trends) ? data.market_analysis.industry_trends : [];
data.market_analysis.competitors = Array.isArray(data.market_analysis.competitors) ? data.market_analysis.competitors : [];
data.market_analysis.regulatory_factors = Array.isArray(data.market_analysis.regulatory_factors) ? data.market_analysis.regulatory_factors : [];
data.market_analysis.barriers_to_entry = Array.isArray(data.market_analysis.barriers_to_entry) ? data.market_analysis.barriers_to_entry : [];
data.market_analysis.opportunities = Array.isArray(data.market_analysis.opportunities) ? data.market_analysis.opportunities : [];
data.market_analysis.tam_sam_som = data.market_analysis.tam_sam_som || {};
data.market_analysis.assumptions = Array.isArray(data.market_analysis.assumptions) ? data.market_analysis.assumptions : [];

return [{ json: data }];
